class Solution:
    def orderOfLargestPlusSign(self, n, mines):
        mineset = set((x, y) for x, y in mines)
        grid = [[0 if (i, j) in mineset else 1 for j in range(n)] for i in range(n)]
        best = 0
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 0:
                    continue
                k = 1
                while True:
                    arm = k
                    if i - arm < 0 or i + arm >= n or j - arm < 0 or j + arm >= n:
                        break
                    if (grid[i - arm][j] and grid[i + arm][j] and grid[i][j - arm] and grid[i][j + arm]):
                        k += 1
                    else:
                        break
                best = max(best, k)
        return best

