var orderOfLargestPlusSign = function(n, mines) {
    const dp = Array.from({length: n}, () => new Array(n).fill(n));
    const mineset = new Set(mines.map(([x, y]) => x * n + y));
    const mined = (i, j) => mineset.has(i * n + j);
    for (let i = 0; i < n; i++) {
        let count = 0;
        for (let j = 0; j < n; j++) {
            count = mined(i, j) ? 0 : count + 1;
            dp[i][j] = Math.min(dp[i][j], count);
        }
        count = 0;
        for (let j = n - 1; j >= 0; j--) {
            count = mined(i, j) ? 0 : count + 1;
            dp[i][j] = Math.min(dp[i][j], count);
        }
    }
    let best = 0;
    for (let j = 0; j < n; j++) {
        let count = 0;
        for (let i = 0; i < n; i++) {
            count = mined(i, j) ? 0 : count + 1;
            dp[i][j] = Math.min(dp[i][j], count);
        }
        count = 0;
        for (let i = n - 1; i >= 0; i--) {
            count = mined(i, j) ? 0 : count + 1;
            dp[i][j] = Math.min(dp[i][j], count);
            best = Math.max(best, dp[i][j]);
        }
    }
    return best;
};
